43	// NewService 创建开发机服务
44	func NewService(k8sClient k8s.Client, cfg *config.Config) Service {
45		// 初始化CSI配置
46		if err := SyncCSIConfigFromStorageClass(k8sClient); err != nil {
47			log.Printf("warning: failed to sync CSI config from storage class: %v", err)
48		}
49	
50		// 启动CSI配置同步循环
51		StartCSISyncLoop(k8sClient)
52	
53		// 启动Ingress URL同步循环
54		StartIngressURLSyncLoop(k8sClient)
55	
56		return &service{k8sClient: k8sClient, config: cfg}
57	}
