144	func (s *service) UpdateDevmachine(ctx context.Context, request *devmachinemodel.UpdateDevmachineRequest) (*devmachinemodel.UpdateDevmachineResponse, error) {
145		// 验证请求参数
146		if err := ValidateDevmachineForModify(request.Name, request.Namespace, request.ImageName); err != nil {
147			return nil, NewValidationError("devmachine", request.Name, err)
148		}
149	
150		// 1. 获取现有 Deployment
151		deployment, err := s.k8sClient.GetDeployment(ctx, request.Namespace, request.Name)
152		if err != nil {
153			return nil, NewResourceError("Deployment", request.Name, "get", err)
154		}
155	
156		// 2. 更新 Deployment 配置
157		deployment.Spec.Template.Spec.Containers[0].Image = request.ImageName
158	
159		// 更新资源请求
160		if request.CPU != "" || request.Memory != "" || request.GPU != "" {
161			// 构建新的资源请求
162			resources := BuildResourceRequirements(request.CPU, request.Memory, request.GPU, request.GPUName)
163			deployment.Spec.Template.Spec.Containers[0].Resources = resources
164		}
165	
166		// 更新节点选择器
167		if len(request.NodeSelector) > 0 {
168			deployment.Spec.Template.Spec.NodeSelector = request.NodeSelector
169		}
170	
171		// 更新标签
172		if len(request.Labels) > 0 {
173			for k, v := range request.Labels {
174				deployment.Labels[k] = v
175				deployment.Spec.Template.Labels[k] = v
176			}
177		}
178	
179		// 更新注解
180		if len(request.Annotations) > 0 {
181			for k, v := range request.Annotations {
182				deployment.Annotations[k] = v
183				deployment.Spec.Template.Annotations[k] = v
184			}
185		}
186	
187		// 更新队列名称
188		if request.QueueName != "" {
189			deployment.Spec.Template.Annotations[volcanoQueueName] = request.QueueName
190		}
191	
192		// 更新默认工作目录
193		if request.WorkDir != "" && len(deployment.Spec.Template.Spec.Containers) > 0 {
194			upsertContainerEnv(&deployment.Spec.Template.Spec.Containers[0], "WORKDIR", request.WorkDir)
195		}
196	
197		// 3. 更新 Deployment
198		if err := s.k8sClient.UpdateDeployment(ctx, deployment); err != nil {
199			return nil, NewResourceError("Deployment", request.Name, "update", err)
200		}
201	
202		// 返回更新时间
203		return &devmachinemodel.UpdateDevmachineResponse{
204			UpdateAt: time.Now().Format(time.RFC3339),
205		}, nil
206	}
