233	func (s *service) GetDevmachine(ctx context.Context, namespace, name string) (*devmachinemodel.GetDevmachineResponse, error) {
234		// 验证请求参数
235		if err := ValidateDevmachineRequest(name, namespace, ""); err != nil && namespace != "" && name != "" {
236			return nil, NewValidationError("devmachine", name, err)
237		}
238	
239		// 获取 Deployment 信息
240		deployment, err := s.k8sClient.GetDeployment(ctx, namespace, name)
241		if err != nil {
242			return nil, NewResourceError("Deployment", name, "get", err)
243		}
244	
245		// 获取 Service 信息
246		service, err := s.k8sClient.GetService(ctx, namespace, name+serviceSuffix)
247		if err != nil {
248			return nil, NewResourceError("Service", name+serviceSuffix, "get", err)
249		}
250	
251		// 获取 Ingress 信息
252		ingress, err := s.k8sClient.GetIngress(ctx, namespace, name+ingressSuffix)
253		if err != nil {
254			return nil, NewResourceError("Ingress", name+ingressSuffix, "get", err)
255		}
256	
257		if deployment == nil || service == nil || ingress == nil {
258			return nil, fmt.Errorf("deployment or service or ingress not found")
259		}
260	
261		// 获取与Deployment关联的存储信息（从 volumeMounts 的 subPath 读取，共享PVC模式）
262		var storage []devmachinemodel.Storage
263		if len(deployment.Spec.Template.Spec.Containers) > 0 {
264			container := deployment.Spec.Template.Spec.Containers[0]
265			for _, vm := range container.VolumeMounts {
266				if vm.Name == SharedRWVolumeName || vm.Name == SharedROVolumeName {
267					storage = append(storage, devmachinemodel.Storage{
268						MountPath:   vm.MountPath,
269						StoragePath: vm.SubPath,
270						ReadOnly:    vm.ReadOnly,
271					})
272				}
273			}
274		}
275	
276		// 提取 GPU 信息
277		gpu := "0"
278		gpuName := ""
279		if len(deployment.Spec.Template.Spec.Containers) > 0 {
280			container := deployment.Spec.Template.Spec.Containers[0]
281			if gpuResource, exists := container.Resources.Requests["hygon.com/dcu"]; exists {
282				gpu = gpuResource.String()
283				gpuName = "hygon.com/dcu"
284			} else if gpuResource, exists := container.Resources.Requests["nvidia.com/gpu"]; exists {
285				gpu = gpuResource.String()
286				gpuName = "nvidia.com/gpu"
287			}
288		}
289	
290		// 获取 WebIDE 类型
291		webIDE := GetWebIDEType(deployment)
292		workDir := defaultWorkDir
293		if len(deployment.Spec.Template.Spec.Containers) > 0 {
294			workDir = getContainerWorkDir(deployment.Spec.Template.Spec.Containers[0])
295		}
296	
297		// 构建响应
298		response := &devmachinemodel.GetDevmachineResponse{
299			Devmachine: devmachinemodel.Devmachine{
300				Namespace:   deployment.Namespace,
301				Name:        deployment.Name,
302				QueueName:   deployment.Spec.Template.Annotations[volcanoQueueName],
303				ImageName:   deployment.Spec.Template.Spec.Containers[0].Image,
304				CPU:         deployment.Spec.Template.Spec.Containers[0].Resources.Requests.Cpu().String(),
305				Memory:      deployment.Spec.Template.Spec.Containers[0].Resources.Requests.Memory().String(),
306				GPU:         gpu,
307				GPUName:     gpuName,
308				WebIDE:      webIDE,
309				WorkDir:     workDir,
310				WebUrl:      fmt.Sprintf("http://%s", GlobalIngressURL+BuildIngressPath(namespace, name)),
311				Storage:     storage,
312				Annotations: deployment.Annotations,
313				Labels:      deployment.Labels,
314			},
315		}
316	
317		// 填充 Pod 级别的细粒度状态
318		status, currentStage, reason, ready, podName := s.resolveStatus(ctx, namespace, deployment)
319		response.Devmachine.Status = status
320		response.Devmachine.CurrentStage = currentStage
321		response.Devmachine.Reason = reason
322		response.Devmachine.Ready = ready
323		response.Devmachine.PodName = podName
324	
325		return response, nil
326	}
