328	func upsertContainerEnv(container *corev1.Container, name, value string) {
329		for i := range container.Env {
330			if container.Env[i].Name == name {
331				container.Env[i].Value = value
332				container.Env[i].ValueFrom = nil
333				return
334			}
335		}
336	
337		container.Env = append(container.Env, corev1.EnvVar{
338			Name:  name,
339			Value: value,
340		})
341	}
342	
343	func getContainerWorkDir(container corev1.Container) string {
344		for _, envVar := range container.Env {
345			if envVar.Name == "WORKDIR" && envVar.Value != "" {
346				return envVar.Value
347			}
348		}
349	
350		return defaultWorkDir
351	}
