463	func (s *service) GetDevmachineStatus(ctx context.Context, namespace, name string) (*devmachinemodel.GetDevmachineStatusResponse, error) {
464		// 验证请求参数
465		if err := ValidateDevmachineRequest(name, namespace, ""); err != nil && namespace != "" && name != "" {
466			return nil, NewValidationError("devmachine", name, err)
467		}
