470		deployment, err := s.k8sClient.GetDeployment(ctx, namespace, name)
471		if err != nil {
472			return nil, NewResourceError("Deployment", name, "get", err)
473		}
474	
475		// 与 GetDevmachine 使用同一套 Pod 级别状态推导逻辑
476		status, currentStage, reason, ready, podName := s.resolveStatus(ctx, namespace, deployment)
477	
