19	const (
20		// PV/PVC 相关常量
21		defaultStorageSize = "10Pi"
22		storageClassName   = "tdsc-sc"
23	)
24	
25	// CSIConfig 存储CSI相关信息
26	type CSIConfig struct {
27		Driver            string                               `json:"driver"`
28		SecretName        string                               `json:"secretName"`
29		SecretNamespace   string                               `json:"secretNamespace"`
30		JuiceFSImage      string                               `json:"juicefsImage"`
31		MountOptions      []string                             `json:"mountOptions"`
32		Parameters        map[string]string                    `json:"parameters"`
33		ReclaimPolicy     corev1.PersistentVolumeReclaimPolicy `json:"reclaimPolicy"`
34		VolumeBindingMode storagev1.VolumeBindingMode          `json:"volumeBindingMode"`
35	}
36	
37	var (
38		csiConfig   *CSIConfig
39		configMutex sync.RWMutex
40	)
41	
42	// GetCSIConfig 获取当前的CSI配置
43	func GetCSIConfig() *CSIConfig {
44		configMutex.RLock()
45		defer configMutex.RUnlock()
46		return csiConfig
47	}
48	
49	// SetCSIConfig 设置CSI配置
50	func SetCSIConfig(config *CSIConfig) {
51		configMutex.Lock()
52		defer configMutex.Unlock()
53		csiConfig = config
54	}
55	
56	// StartCSISyncLoop 启动CSI配置同步循环
57	func StartCSISyncLoop(k8sClient k8s.Client) {
58		// 使用wait.Until启动定时同步循环
59		go wait.Until(func() {
60			// 获取StorageClass信息
61			sc, err := getStorageClassInfo(k8sClient, storageClassName)
62			if err != nil {
63				// 记录错误但继续运行
64				return
65			}
66			// 更新CSI配置
67			SetCSIConfig(sc)
68		}, 30*time.Second, wait.NeverStop)
69	}
70	
71	// getStorageClassInfo 从k8s获取StorageClass信息并转换为CSIConfig
72	func getStorageClassInfo(k8sClient k8s.Client, className string) (*CSIConfig, error) {
73		ctx := context.Background()
74		if k8sClient == nil {
75			return nil, fmt.Errorf("k8s client is nil")
76		}
77		sc, err := k8sClient.GetStorageClass(ctx, className)
78		if err != nil {
79			return nil, fmt.Errorf("failed to get storage class %s: %w", className, err)
80		}
81	
82		config := &CSIConfig{
83			Driver:            sc.Provisioner,
84			ReclaimPolicy:     *sc.ReclaimPolicy,
85			VolumeBindingMode: *sc.VolumeBindingMode,
86			Parameters:        make(map[string]string),
87			MountOptions:      make([]string, len(sc.MountOptions)),
88		}
89	
90		// 复制参数
91		for k, v := range sc.Parameters {
92			config.Parameters[k] = v
93		}
94	
95		// 复制挂载选项
96		copy(config.MountOptions, sc.MountOptions)
97	
98		// 从参数中提取 Secret 信息
99		if secretName, exists := config.Parameters["csi.storage.k8s.io/node-publish-secret-name"]; exists {
100			config.SecretName = secretName
101		}
102		if secretNamespace, exists := config.Parameters["csi.storage.k8s.io/node-publish-secret-namespace"]; exists {
103			config.SecretNamespace = secretNamespace
104		}
105		if juiceFSImage, exists := config.Parameters["juicefs/mount-image"]; exists {
106			config.JuiceFSImage = juiceFSImage
107		}
108	
109		return config, nil
110	}
111	
112	// SyncCSIConfigFromStorageClass 从StorageClass同步CSI配置
113	func SyncCSIConfigFromStorageClass(k8sClient k8s.Client) error {
114		sc, err := getStorageClassInfo(k8sClient, storageClassName)
115		if err != nil {
116			return fmt.Errorf("failed to get storage class info: %w", err)
117		}
118		SetCSIConfig(sc)
119		return nil
120	}
121	
122	// ==================== 共享存储构建 ====================
123	
124	// buildSharedPV 构建共享 PersistentVolume
125	// 使用集群级别共享 PV，ReclaimPolicy 为 Retain（区别于旧的 Delete）
126	func buildSharedPV(name, subPath string, readOnly bool) (*corev1.PersistentVolume, error) {
127		configMutex.RLock()
128		defer configMutex.RUnlock()
129	
130		if csiConfig == nil {
131			return nil, fmt.Errorf("CSI config not initialized, cannot build shared PV %s", name)
132		}
133	
134		accessMode := corev1.ReadWriteMany
135		if readOnly {
136			accessMode = corev1.ReadOnlyMany
137		}
138	
139		volumeMode := corev1.PersistentVolumeFilesystem
140		pv := &corev1.PersistentVolume{
141			ObjectMeta: metav1.ObjectMeta{
142				Name: name,
143			},
144			Spec: corev1.PersistentVolumeSpec{
145				Capacity: corev1.ResourceList{
146					corev1.ResourceStorage: resource.MustParse(defaultStorageSize),
147				},
148				VolumeMode:                    &volumeMode,
149				AccessModes:                   []corev1.PersistentVolumeAccessMode{accessMode},
150				PersistentVolumeReclaimPolicy: corev1.PersistentVolumeReclaimRetain,
151				PersistentVolumeSource: corev1.PersistentVolumeSource{
152					CSI: &corev1.CSIPersistentVolumeSource{
153						Driver: csiConfig.Driver,
154						FSType: "juicefs",
155						NodePublishSecretRef: &corev1.SecretReference{
156							Name:      csiConfig.SecretName,
157							Namespace: csiConfig.SecretNamespace,
158						},
159						VolumeHandle:     name,
160						VolumeAttributes: map[string]string{},
161					},
162				},
163			},
164		}
165	
166		if csiConfig.MountOptions != nil {
167			pv.Spec.MountOptions = csiConfig.MountOptions
168		}
169		for k, v := range csiConfig.Parameters {
170			pv.Spec.CSI.VolumeAttributes[k] = v
171		}
172		if subPath != "" {
173			pv.Spec.CSI.VolumeAttributes["subPath"] = subPath
174		}
175	
176		return pv, nil
177	}
178	
179	// buildSharedPVC 构建 namespace 级共享 PersistentVolumeClaim
180	// 通过 spec.volumeName 显式绑定到集群共享 PV
181	func buildSharedPVC(namespace, pvcName, pvName string, readOnly bool) *corev1.PersistentVolumeClaim {
182		accessMode := corev1.ReadWriteMany
183		if readOnly {
184			accessMode = corev1.ReadOnlyMany
185		}
186	
187		storageClass := ""
188		return &corev1.PersistentVolumeClaim{
189			ObjectMeta: metav1.ObjectMeta{
190				Name:      pvcName,
191				Namespace: namespace,
192			},
193			Spec: corev1.PersistentVolumeClaimSpec{
194				VolumeName:       pvName,
195				AccessModes:      []corev1.PersistentVolumeAccessMode{accessMode},
196				StorageClassName: &storageClass,
197				Resources: corev1.VolumeResourceRequirements{
198					Requests: corev1.ResourceList{
199						corev1.ResourceStorage: resource.MustParse(defaultStorageSize),
200					},
201				},
202			},
203		}
204	}
205	
206	// buildSharedVolumes 根据 storage 列表构建共享卷（去重，最多 2 个）
207	// ReadOnly=false 的 storage 共用 shared-rw-volume
208	// ReadOnly=true  的 storage 共用 shared-ro-volume
209	func buildSharedVolumes(storages []devmachinemodel.Storage) []corev1.Volume {
210		if len(storages) == 0 {
211			return nil
212		}
213	
214		volumes := make([]corev1.Volume, 0, 2)
215		hasRW, hasRO := false, false
216	
217		for _, s := range storages {
218			if !s.ReadOnly && !hasRW {
219				hasRW = true
220				volumes = append(volumes, corev1.Volume{
221					Name: SharedRWVolumeName,
222					VolumeSource: corev1.VolumeSource{
223						PersistentVolumeClaim: &corev1.PersistentVolumeClaimVolumeSource{
224							ClaimName: SharedRWPVCName,
225						},
226					},
227				})
228			}
229			if s.ReadOnly && !hasRO {
230				hasRO = true
231				volumes = append(volumes, corev1.Volume{
232					Name: SharedROVolumeName,
233					VolumeSource: corev1.VolumeSource{
234						PersistentVolumeClaim: &corev1.PersistentVolumeClaimVolumeSource{
235							ClaimName: SharedROPVCName,
236							ReadOnly:  true,
237						},
238					},
239				})
240			}
241		}
242	
243		return volumes
244	}
245	
246	// buildSharedVolumeMounts 构建共享卷挂载列表（每条 storage 独立挂载，subPath 隔离）
247	func buildSharedVolumeMounts(storages []devmachinemodel.Storage) []corev1.VolumeMount {
248		if len(storages) == 0 {
249			return nil
250		}
251	
252		mounts := make([]corev1.VolumeMount, 0, len(storages))
253		for _, s := range storages {
254			volName := SharedRWVolumeName
255			if s.ReadOnly {
256				volName = SharedROVolumeName
257			}
258			mounts = append(mounts, corev1.VolumeMount{
259				Name:      volName,
260				MountPath: s.MountPath,
261				SubPath:   s.StoragePath,
262				ReadOnly:  s.ReadOnly,
263			})
264		}
265	
266		return mounts
267	}
