19	// Detect 检测WebIDE类型
20	func (d *DefaultWebIDETypeDetector) Detect(imageName string) devmachinemodel.WebIDEType {
21		lowerImageName := strings.ToLower(imageName)
22		if strings.Contains(lowerImageName, string(devmachinemodel.WebIDEJupyter)) {
23			return devmachinemodel.WebIDEJupyter
24		} else if strings.Contains(lowerImageName, string(devmachinemodel.WebIDEVSCode)) {
